import{_ as t,o as e,c as n,a2 as i}from"./chunks/framework.CHeM0PsO.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"pengantar/apa-itu-zero-cafe.md","filePath":"pengantar/apa-itu-zero-cafe.md","lastUpdated":1784467494000}'),r={name:"pengantar/apa-itu-zero-cafe.md"};function s(o,a,d,l,u,m){return e(),n("div",null,[...a[0]||(a[0]=[i('<h2 id="bab-1-apa-itu-zero-cafe-app-kenapa-dibuat" tabindex="-1">BAB 1: APA ITU ZERO CAFE APP &amp; KENAPA DIBUAT <a class="header-anchor" href="#bab-1-apa-itu-zero-cafe-app-kenapa-dibuat" aria-label="Permalink to &quot;BAB 1: APA ITU ZERO CAFE APP &amp; KENAPA DIBUAT&quot;">​</a></h2><h3 id="_1-1-latar-belakang" tabindex="-1">1.1 Latar Belakang <a class="header-anchor" href="#_1-1-latar-belakang" aria-label="Permalink to &quot;1.1 Latar Belakang&quot;">​</a></h3><p>Zero Cafe App adalah aplikasi pelaporan operasional harian yang dibangun secara khusus oleh <strong>Acronimous Studio</strong> untuk Zero Cafe. Aplikasi ini bukan aplikasi kasir (POS), bukan aplikasi stok, dan bukan aplikasi akuntansi. Fungsi utamanya adalah <strong>menjadi mata dan telinga pemilik (owner) di outlet yang tidak bisa dikunjungi setiap hari</strong>.</p><p>Melalui aplikasi ini:</p><ul><li><strong>Supervisor (SPV)</strong> melaporkan kondisi lapangan secara terstruktur setiap hari.</li><li><strong>General Manager (GM/Owner)</strong> memantau kesehatan bisnis melalui Dashboard yang menampilkan angka-angka kunci secara otomatis.</li></ul><h3 id="_1-2-filosofi-data-driven-disciplinary" tabindex="-1">1.2 Filosofi: Data-Driven Disciplinary <a class="header-anchor" href="#_1-2-filosofi-data-driven-disciplinary" aria-label="Permalink to &quot;1.2 Filosofi: Data-Driven Disciplinary&quot;">​</a></h3><p>Setiap data yang diketik SPV bukan sekadar formalitas. Angka-angka tersebut dihitung secara otomatis oleh mesin di balik layar untuk menghasilkan <strong>4 Indikator Kunci (KPI)</strong> yang menentukan sehat atau tidaknya operasional kafe:</p><table tabindex="0"><thead><tr><th>No</th><th>KPI</th><th>Target</th><th>Artinya</th></tr></thead><tbody><tr><td>1</td><td><strong>Kepatuhan SOP (Keramahan)</strong></td><td>≥ 95%</td><td>Seberapa sering staf menyapa dan melayani pelanggan dengan ramah</td></tr><tr><td>2</td><td><strong>Rata-rata Penjualan Harian</strong></td><td>Tidak boleh turun dari target bulanan</td><td>Omset harian harus konsisten menuju target</td></tr><tr><td>3</td><td><strong>Komplain Pelanggan Serius</strong></td><td>Maksimal 2 per bulan</td><td>Lebih dari 2 komplain = alarm merah</td></tr><tr><td>4</td><td><strong>Turnover Barista</strong></td><td>Maksimal 1 orang per 3 bulan</td><td>Staf yang keluar terlalu sering = operasional terganggu</td></tr></tbody></table><p>Keempat angka ini muncul di halaman pertama Dashboard GM sebagai <strong>&quot;Ringkasan 4 KPI Utama&quot;</strong> — sehingga owner cukup membuka aplikasi dan dalam 3 detik sudah tahu kondisi kafe.</p><h3 id="_1-3-mekanisme-dua-fase-fase-1-fase-2" tabindex="-1">1.3 Mekanisme Dua Fase (Fase 1 &amp; Fase 2) <a class="header-anchor" href="#_1-3-mekanisme-dua-fase-fase-1-fase-2" aria-label="Permalink to &quot;1.3 Mekanisme Dua Fase (Fase 1 &amp; Fase 2)&quot;">​</a></h3><p>Karena outlet Zero Cafe beroperasi hingga larut malam (Perintis tutup jam 04:00 dini hari), tidak mungkin menunggu semua data selesai baru mengirim laporan. Oleh karena itu, pelaporan harian dibagi menjadi <strong>dua tahap</strong>:</p><table tabindex="0"><thead><tr><th>Fase</th><th>Kapan</th><th>Siapa</th><th>Isi</th></tr></thead><tbody><tr><td><strong>Fase 1 (Malam)</strong></td><td>Saat SPV selesai shift (±21:00)</td><td>SPV</td><td>9 Tab inspeksi: Penjualan Shift 1, Kas, Staf, Briefing, QC, Kebersihan, Komplain, Fasilitas, Penutup</td></tr><tr><td><strong>Fase 2 (Pagi Besoknya)</strong></td><td>Sebelum jam 13:00 siang keesokan hari</td><td>SPV</td><td>Omset Shift 2, Total Struk Transaksi, Evaluasi Produk (Top 5 &amp; Bottom 3), Komplain Susulan Malam, Absensi Staf Malam</td></tr></tbody></table><p><strong>Apa yang terjadi di balik layar?</strong> Saat SPV menekan tombol &quot;Kirim&quot; di Fase 1, sistem <strong>belum mencetak PDF</strong>. Sistem menyimpan data sementara dalam bentuk file cadangan (Draft JSON) di Google Drive. Keesokan paginya, saat SPV mengirim Fase 2, sistem menggabungkan kedua data, mencetak PDF final, dan menyimpan laporan lengkap ke database.</p><h3 id="_1-4-jam-operasional-outlet" tabindex="-1">1.4 Jam Operasional Outlet <a class="header-anchor" href="#_1-4-jam-operasional-outlet" aria-label="Permalink to &quot;1.4 Jam Operasional Outlet&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Outlet</th><th>Buka</th><th>Tutup</th></tr></thead><tbody><tr><td><strong>Perintis</strong></td><td>08:00</td><td>04:00 (dini hari, setiap hari)</td></tr><tr><td><strong>Dg Tata</strong></td><td>08:00</td><td>24:00 (Minggu–Kamis) / 01:00 (Jumat–Sabtu)</td></tr></tbody></table><p><strong>Jam Kerja SPV:</strong> 12:00 siang – 21:00 malam (sama untuk kedua outlet).</p><h3 id="_1-5-batas-waktu-laporan-streak" tabindex="-1">1.5 Batas Waktu Laporan (Streak) <a class="header-anchor" href="#_1-5-batas-waktu-laporan-streak" aria-label="Permalink to &quot;1.5 Batas Waktu Laporan (Streak)&quot;">​</a></h3><p>Untuk mendorong kedisiplinan, sistem memiliki fitur <strong>Streak</strong> (rantai keberhasilan):</p><ul><li><strong>Batas Akhir:</strong> Laporan Fase 2 <strong>wajib dikirim sebelum jam 13:00 (1 siang) keesokan harinya</strong>.</li><li>Jika terlambat melewati batas waktu tersebut, rantai Streak SPV akan <strong>putus</strong>.</li><li>Streak ini terlihat di Dashboard GM sebagai indikator kedisiplinan SPV.</li></ul><hr>',20)])])}const g=t(r,[["render",s]]);export{k as __pageData,g as default};
